instance.invitation-mail:
invitation -> applicationName -> link -> {
  emailBody = {{{<p>
Dear Recipient,
</p>
<p>
You have been invited to create an account for the application {$applicationName}.
</p>
<p>
To begin the setup process, please open the link and follow the instructions on the website:<br/>
<a href="{$link}">{$link}</a>
</p>
<p>
If you did not expect this invitation, you can safely ignore this email.
</p>
<p>
Kind regards,<br/>
Your {$applicationName} Team
</p>}}};
  subject = "Invitation to " + $applicationName;
  emailAddr = $invitation.get(`tl.security.selfservice:Invitation#email`);

  try(
    sendMail(
      subject: $subject,
      to: $emailAddr,
      body: $emailBody
    ),
    catch: mailError -> {
      info("Sending mail to " + $emailAddr + " failed. reason: " + $mailError);
      false
    }
  );
}

instance.verification-mail:
invitation -> applicationName -> code -> {
  emailBody = {{{<p>
Dear Recipient,
</p>
<p>
Please enter the following verification code in the application to continue:<br/>
<b>Verification Code:</b> {$code}
</p>
<p>
This verification code is only valid for a limited time.
</p>
<p>
If you did not expect this invitation, you can safely ignore this email.
</p>
<p>
Kind regards,<br/>
Your {$applicationName} Team
</p>}}};
  subject = "Your verification code";
  emailAddr = $invitation.get(`tl.security.selfservice:Invitation#email`);

  try(
    sendMail(
      subject: $subject,
      to: $emailAddr,
      body: $emailBody
    ),
    catch: mailError -> {
      info("Sending mail to " + $emailAddr + " failed. reason: " + $mailError);
      false
    }
  );
}
